SELECT id, recording_id, user_id, item_id, label, vocabulary_type, forgetting_score, recommendation,
       mastery_level, next_review_at, score_source, updated_at
FROM vocabulary_weak_points
WHERE user_id = #{userId}

    AND vocabulary_type = #{vocabularyType}

ORDER BY forgetting_score DESC

SELECT id, recording_id, user_id, item_id, label, vocabulary_type, forgetting_score, recommendation,
       mastery_level, next_review_at, score_source, updated_at
FROM vocabulary_weak_points
WHERE user_id = #{userId}
ORDER BY forgetting_score DESC
LIMIT #{limit}
